467	func PruneLayers() error {
468		deleteMap := make(map[string]struct{})
469		p, err := manifest.BlobsPath("")
470		if err != nil {
471			return err
472		}
473	
474		blobs, err := os.ReadDir(p)
475		if err != nil {
476			slog.Info(fmt.Sprintf("couldn't read dir '%s': %v", p, err))
477			return err
478		}
479	
480		for _, blob := range blobs {
481			name := blob.Name()
482			name = strings.ReplaceAll(name, "-", ":")
483	
484			_, err := manifest.BlobsPath(name)
485			if err != nil {
486				if errors.Is(err, manifest.ErrInvalidDigestFormat) {
487					// remove invalid blobs (e.g. partial downloads)
488					if err := os.Remove(filepath.Join(p, blob.Name())); err != nil {
489						slog.Error("couldn't remove blob", "blob", blob.Name(), "error", err)
490					}
491				}
492	
493				continue
494			}
495	
496			deleteMap[name] = struct{}{}
497		}
498	
499		slog.Info(fmt.Sprintf("total blobs: %d", len(deleteMap)))
500	
501		if err := deleteUnusedLayers(deleteMap); err != nil {
502			slog.Error(fmt.Sprintf("couldn't remove unused layers: %v", err))
503			return nil
504		}
505	
506		slog.Info(fmt.Sprintf("total unused blobs removed: %d", len(deleteMap)))
507	
508		return nil
509	}
