## Ollama Server-Side Code Exploration Report

I've thoroughly explored the Ollama server codebase. Here's a complete analysis of the copy handler, delete handler, model storage, and error handling:

---

### 1. COPY HANDLER IMPLEMENTATION

**Location:** `/server/routes.go:1446-1483`

```go
func (s *Server) CopyHandler(c *gin.Context) {
	var r api.CopyRequest
	if err := c.ShouldBindJSON(&r); errors.Is(err, io.EOF) {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "missing request body"})
		return
	} else if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	src := model.ParseName(r.Source)
	if !src.IsValid() {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("source %q is invalid", r.Source)})
		return
	}
	src, err := getExistingName(src)
	if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	dst := model.ParseName(r.Destination)
	if !dst.IsValid() {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("destination %q is invalid", r.Destination)})
		return
	}
	dst, err = getExistingName(dst)
	if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := CopyModel(src, dst); errors.Is(err, os.ErrNotExist) {
		c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model %q not found", r.Source)})
	} else if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
	}
}
```

**Key aspects:**
- Validates both source and destination model names using `ParseName()` and `IsValid()`
- Uses `getExistingName()` to canonicalize names (case correction via case-insensitive lookups)
- Returns 404 (NotFound) if source model doesn't exist (`os.ErrNotExist`)
- Returns 500 (InternalServerError) for other errors
- **No 409 Conflict error** - allows overwriting destination if it exists

---

### 2. DELETE HANDLER IMPLEMENTATION

**Location:** `/server/routes.go:1055-1104`

```go
func (s *Server) DeleteHandler(c *gin.Context) {
	var r api.DeleteRequest
	if err := c.ShouldBindJSON(&r); errors.Is(err, io.EOF) {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "missing request body"})
		return
	} else if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	modelRef, err := parseNormalizePullModelRef(cmp.Or(r.Model, r.Name))
	if err != nil {
		switch {
		case errors.Is(err, errConflictingModelSource):
			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		case errors.Is(err, model.ErrUnqualifiedName):
			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("name %q is invalid", cmp.Or(r.Model, r.Name))})
		default:
			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		}
		return
	}

	n, err := getExistingName(modelRef.Name)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model '%s' not found", cmp.Or(r.Model, r.Name))})
		return
	}

	m, err := manifest.ParseNamedManifest(n)
	if err != nil {
		switch {
		case os.IsNotExist(err):
			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model '%s' not found", cmp.Or(r.Model, r.Name))})
		default:
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		}
		return
	}

	if err := m.Remove(); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if err := m.RemoveLayers(); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
}
```

**Key aspects:**
- Uses `parseNormalizePullModelRef()` to parse model reference
- Calls `getExistingName()` to canonicalize the model name
- Parses the manifest using `manifest.ParseNamedManifest()`
- Calls two removal operations: `m.Remove()` and `m.RemoveLayers()`
- Returns 404 if model not found
- Returns 500 for operational errors

---

### 3. STORAGE-LEVEL COPY FUNCTION

**Location:** `/server/images.go:397-434`

```go
func CopyModel(src, dst model.Name) error {
	if !dst.IsFullyQualified() {
		return model.Unqualified(dst)
	}
	if !src.IsFullyQualified() {
		return model.Unqualified(src)
	}

	if src.Filepath() == dst.Filepath() {
		return nil
	}

	manifests, err := manifest.Path()
	if err != nil {
		return err
	}

	dstpath := filepath.Join(manifests, dst.Filepath())
	if err := os.MkdirAll(filepath.Dir(dstpath), 0o755); err != nil {
		return err
	}

	srcpath := filepath.Join(manifests, src.Filepath())
	srcfile, err := os.Open(srcpath)
	if err != nil {
		return err
	}
	defer srcfile.Close()

	dstfile, err := os.Create(dstpath)
	if err != nil {
		return err
	}
	defer dstfile.Close()

	_, err = io.Copy(dstfile, srcfile)
	return err
}
```

**Key aspects:**
- Validates both names are fully qualified
- Returns early if source and destination are identical
- Copies only the **manifest file**, not the blob layers
- Creates destination directory structure if needed
- Performs file-level copy using `io.Copy()`
- **No conflict detection** - silently overwrites if destination exists

---

### 4. STORAGE-LEVEL DELETE FUNCTIONS

**Location:** `/manifest/manifest.go:61-110`

**Function 1: `Manifest.Remove()`**
```go
func (m *Manifest) Remove() error {
	if err := os.Remove(m.filepath); err != nil {
		return err
	}

	manifests, err := manifest.Path()
	if err != nil {
		return err
	}

	return PruneDirectory(manifests)
}
```

**Function 2: `Manifest.RemoveLayers()`**
```go
func (m *Manifest) RemoveLayers() error {
	ms, err := Manifests(true)
	if err != nil {
		return err
	}

	// Build set of digests still in use by other manifests
	inUse := make(map[string]struct{})
	for _, other := range ms {
		for _, layer := range append(other.Layers, other.Config) {
			if layer.Digest != "" {
				inUse[layer.Digest] = struct{}{}
			}
		}
	}

	// Remove layers not used by any other manifest
	for _, layer := range append(m.Layers, m.Config) {
		if layer.Digest == "" {
			continue
		}
		if _, used := inUse[layer.Digest]; used {
			continue
		}
		blob, err := BlobsPath(layer.Digest)
		if err != nil {
			return err
		}
		if err := os.Remove(blob); os.IsNotExist(err) {
			slog.Debug("layer does not exist", "digest", layer.Digest)
		} else if err != nil {
			return err
		}
	}

	return nil
}
```

**Key aspects:**
- `Remove()`: Deletes the manifest file and prunes empty directories
- `RemoveLayers()`: Only deletes blob layers NOT referenced by other manifests (garbage collection)
- Prevents accidental deletion of shared blobs used by other models
- Continues gracefully if blobs already don't exist

---

### 5. MODEL STORAGE AND REGISTRY

**Model Name Structure:**
- Fully qualified names have 4 parts: `{host}/{namespace}/{model}/{tag}`
- Example: `registry.ollama.ai/library/llama2/latest`
- Default host: `registry.ollama.ai`
- Default namespace: `library`
- Default tag: `latest`

**Storage Paths:**

**Manifests Path:**
```
$OLLAMA_MODELS/manifests/{host}/{namespace}/{model}/{tag}
```
File format: JSON manifest containing layer references and config

**Blobs Path:**
```
$OLLAMA_MODELS/blobs/sha256-{64-hex-chars}
```
Files: Raw blob data (model weights, config JSON, etc.)

**Location:** `/manifest/paths.go:17-61`
```go
func Path() (string, error) {
	path := filepath.Join(envconfig.Models(), "manifests")
	if err := os.MkdirAll(path, 0o755); err != nil {
		return "", fmt.Errorf("%w: ensure path elements are traversable", err)
	}
	return path, nil
}

func PathForName(n model.Name) (string, error) {
	if !n.IsValid() {
		return "", os.ErrNotExist
	}
	manifests, err := Path()
	if err != nil {
		return "", err
	}
	return filepath.Join(manifests, n.Filepath()), nil
