    if err != nil {
        // Error handling
        c.JSON(http.StatusNotFound, gin.H{"error": "model not found"})
        return
    }

    // Remove manifest and layers
    if err := m.Remove(); err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
