### 6. **Model Copy Implementation** (`/server/images.go`, lines 397-434)

```go
func CopyModel(src, dst model.Name) error {
    // Validate both names are fully qualified
    if !dst.IsFullyQualified() {
        return model.Unqualified(dst)
    }
    if !src.IsFullyQualified() {
        return model.Unqualified(src)
    }

    // Short-circuit if source and destination are the same
    if src.Filepath() == dst.Filepath() {
        return nil
    }

    // Get the manifests directory path
    manifests, err := manifest.Path()
    if err != nil {
        return err
    }

    // Create destination directory
    dstpath := filepath.Join(manifests, dst.Filepath())
    if err := os.MkdirAll(filepath.Dir(dstpath), 0o755); err != nil {
        return err
    }

    // Open source manifest
    srcpath := filepath.Join(manifests, src.Filepath())
    srcfile, err := os.Open(srcpath)
    if err != nil {
        return err
    }
    defer srcfile.Close()

    // Create destination manifest
    dstfile, err := os.Create(dstpath)
    if err != nil {
        return err
    }
    defer dstfile.Close()

    // Copy file contents (manifest file, not the layers)
    _, err = io.Copy(dstfile, srcfile)
    return err
}
```

**Key insight:** This function copies the **manifest file only** (metadata), not the actual model layers/blobs. The layers are shared between models to save space.

